+func TestFocusRingEmpty(t *testing.T) {
+	t.Parallel()
+
+	fr := NewFocusRing(nil)
+	fr.Next()
+	fr.Prev()
+	if fr.Current().ID != "" {
+		t.Fatalf("expected empty focus ring, got %q", fr.Current().ID)
+	}
+}
